const input = $input.first();
const body = input.json.body || input.json || {};
const binary = input.binary || {};
const binaryKeys = Object.keys(binary);

function parseJsonMaybe(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;
  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch (_) {
      return fallback;
    }
  }
  return fallback;
}

function toNumber(value, fallback = null) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "number") return Number.isFinite(value) ? value : fallback;

  let s = String(value)
    .replace(/US\$/gi, "")
    .replace(/\$/g, "")
    .replace(/CLP|USD|EUR/gi, "")
    .replace(/[()]/g, "")
    .replace(/\s/g, "")
    .replace(/[^\d.,-]/g, "")
    .trim();

  if (!s) return fallback;

  const hasComma = s.includes(",");
  const hasDot = s.includes(".");

  if (hasComma && hasDot) {
    s = s.lastIndexOf(",") > s.lastIndexOf(".")
      ? s.replace(/\./g, "").replace(",", ".")
      : s.replace(/,/g, "");
  } else if (hasComma && !hasDot) {
    const parts = s.split(",");
    s = parts.length === 2 && parts[1].length <= 2
      ? parts[0].replace(/\./g, "") + "." + parts[1]
      : s.replace(/,/g, "");
  } else if (hasDot && !hasComma) {
    const parts = s.split(".");
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3)) {
      s = s.replace(/\./g, "");
    }
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : fallback;
}

function parseSizeBytes(value) {
  if (value === undefined || value === null || value === "") return 0;
  if (typeof value === "number") return value;

  const raw = String(value).trim().toLowerCase();
  const n = Number(raw.replace(",", ".").replace(/[^\d.]/g, ""));

  if (!Number.isFinite(n)) return 0;

  if (raw.includes("gb")) return Math.round(n * 1024 * 1024 * 1024);
  if (raw.includes("mb")) return Math.round(n * 1024 * 1024);
  if (raw.includes("kb")) return Math.round(n * 1024);

  return Math.round(n);
}

function extOf(fileName) {
  return String(fileName || "").split(".").pop().toLowerCase();
}

const evaluationRaw = parseJsonMaybe(body.evaluationDataJson || body.evaluationData, {});
const providerVariables = parseJsonMaybe(
  body.providerVariablesJson || body.providerVariables || evaluationRaw.providerVariables,
  []
);

const exchange = {
  mode: String(body.exchangeRateMode || body.exchangeMode || "auto"),
  baseRate: toNumber(body.exchangeRateBase || body.baseRate, null),
  marginClp: toNumber(body.exchangeRateMarginClp ?? body.marginClp, 0),
  manualRate: toNumber(body.exchangeRateManual || body.manualRate, null),
  finalRate: toNumber(body.exchangeRateFinal || body.finalRate, null),
  targetCurrency: String(body.targetCurrency || "CLP").toUpperCase()
};

const evaluationData = {
  ...evaluationRaw,
  responsableAdjudicacion:
    body.responsableAdjudicacion ||
    body.awardingResponsible ||
    evaluationRaw.responsableAdjudicacion ||
    null,
  compradorResponsable:
    body.compradorResponsable ||
    body.buyerResponsible ||
    evaluationRaw.compradorResponsable ||
    null,
  gradoUrgencia:
    body.gradoUrgencia ||
    body.urgencyLevel ||
    evaluationRaw.gradoUrgencia ||
    null,
  presupuestoObjetivo: toNumber(
    body.presupuestoObjetivo || body.targetBudget || evaluationRaw.presupuestoObjetivo,
    null
  ),
  criterioAdjudicacion:
    body.criterioAdjudicacion ||
    body.adjudicationCriteria ||
    evaluationRaw.criterioAdjudicacion ||
    null,
  providerVariables: Array.isArray(providerVariables) ? providerVariables : []
};

const requestContext = {
  jobId: String(body.jobId || body.sessionId || `EMBUDO-${Date.now()}`),
  exchange,
  evaluationData
};

const maxBytes = 15 * 1024 * 1024;
const output = [];
const omittedFiles = [];
const warnings = [];

if (binaryKeys.length === 0) {
  return [
    {
      json: {
        noValidPdf: true,
        ok: false,
        statusCode: 400,
        ...requestContext,
        summary: {
          filesReceived: 0,
          filesAccepted: 0,
          omittedFiles: 0
        },
        documents: [],
        validDocuments: [],
        validQuotations: [],
        omittedFiles: [],
        warnings: [],
        errors: ["No se recibieron archivos."]
      }
    }
  ];
}

for (let index = 0; index < binaryKeys.length; index++) {
  const key = binaryKeys[index];
  const file = binary[key];

  const fileName = file.fileName || file.filename || `archivo_${index + 1}.pdf`;
  const ext = extOf(fileName);
  const mimeType = file.mimeType || file.type || "";
  const fileSize = parseSizeBytes(file.fileSize || file.fileSizeBytes || 0);

  const isPdfExt = ext === "pdf";
  const isPdfMime = !mimeType || String(mimeType).toLowerCase().includes("pdf");

  if (!isPdfExt || !isPdfMime) {
    omittedFiles.push({
      fileName,
      fileKind: "unsupported",
      ext,
      mimeType: mimeType || "application/octet-stream",
      reason: "unsupported_file",
      warnings: ["Solo se aceptan archivos PDF en esta versión."]
    });
    warnings.push(`${fileName}: archivo omitido porque no es PDF.`);
    continue;
  }

  if (fileSize > maxBytes) {
    omittedFiles.push({
      fileName,
      fileKind: "pdf",
      ext,
      mimeType: "application/pdf",
      fileSize,
      reason: "too_large",
      warnings: ["El archivo supera el máximo permitido de 15 MB."]
    });
    warnings.push(`${fileName}: archivo omitido porque supera 15 MB.`);
    continue;
  }

  output.push({
    json: {
      noValidPdf: false,
      ok: true,
      fileIndex: output.length,
      fileName,
      fileKind: "pdf",
      ext: "pdf",
      mimeType: "application/pdf",
      fileSize,
      originalBinaryKey: key,
      omittedFiles: [...omittedFiles],
      warnings: [...warnings],
      errors: [],
      ...requestContext
    },
    binary: {
      data: {
        ...file,
        fileName,
        filename: fileName,
        mimeType: "application/pdf"
      }
    }
  });
}

if (output.length === 0) {
  return [
    {
      json: {
        noValidPdf: true,
        ok: false,
        statusCode: 400,
        ...requestContext,
        summary: {
          filesReceived: binaryKeys.length,
          filesAccepted: 0,
          omittedFiles: omittedFiles.length
        },
        documents: [],
        validDocuments: [],
        validQuotations: [],
        omittedFiles,
        warnings,
        errors: ["No se recibió ningún PDF válido."]
      }
    }
  ];
}

return output;

/* ============================================================================
 * EMBUDO v2 - Build Deterministic Final Response
 * Parser deterministico GENERICO basado en el invariante  qty * unit ~= total.
 *
 * pdf-parse destruye el layout de las tablas y concatena columnas sin separador
 * (ej. "1K75404Kensington Mouse...33,0033,00"). Este parser:
 *   - reconstruye filas tokenizando numeros (separando decimales pegados),
 *   - acepta una fila SOLO si cantidad * precioUnit ~= total  -> elimina la
 *     basura (fechas, RUT, telefonos, cuentas, P/N no cumplen el invariante),
 *   - detecta proveedor por RUT conocido / "Emitir OC" / NOMBRE / dominio,
 *   - nunca usa al cliente (Master Drilling) como proveedor,
 *   - convierte USD->CLP con exchange.finalRate,
 *   - calcula subtotal = suma(items + costos), IVA 19%, total.
 *
 * NO hardcodea productos ni precios: funciona con cotizaciones nuevas de los
 * mismos proveedores y con otros proveedores en formatos distintos.
 *
 * Contrato de salida intacto: ok, source, jobId, exchange, evaluationData,
 * summary, documents, validDocuments, validQuotations, omittedFiles,
 * warnings, errors.  Cada PDF -> exactamente un document.
 * ==========================================================================*/

const sourceItems = $input.all();

/* --------------------------------- utils -------------------------------- */
function asText(v) { return v === null || v === undefined ? "" : String(v); }
function compact(v) { return asText(v).replace(/\s+/g, " ").trim(); }
function norm(v) {
  return asText(v).replace(/\r\n/g, "\n").replace(/\r/g, "\n")
    .replace(/�/g, "").replace(/[ \t]+/g, " ").replace(/\n[ \t]+/g, "\n")
    .replace(/\n{3,}/g, "\n\n").trim();
}
function stripAcc(v) { return asText(v).normalize("NFD").replace(/[̀-ͯ]/g, ""); }
function normSearch(v) { return stripAcc(asText(v)).toLowerCase().replace(/\s+/g, " ").trim(); }

function toNum(value, fallback) {
  if (fallback === undefined) fallback = null;
  if (value === null || value === undefined || value === "") return fallback;
  if (typeof value === "number") return Number.isFinite(value) ? value : fallback;
  let s = String(value)
    .replace(/US\$/gi, "").replace(/\$/g, "").replace(/CLP|USD|EUR/gi, "")
    .replace(/[()]/g, "").replace(/\s/g, "").replace(/\.-$/g, "").replace(/-$/g, "")
    .replace(/[^\d.,-]/g, "").trim();
  if (!s || s === "-" || s === "." || s === ",") return fallback;
  const hasComma = s.includes(","), hasDot = s.includes(".");
  if (hasComma && hasDot) {
    s = s.lastIndexOf(",") > s.lastIndexOf(".")
      ? s.replace(/\./g, "").replace(",", ".")
      : s.replace(/,/g, "");
  } else if (hasComma && !hasDot) {
    const parts = s.split(",");
    s = parts.length === 2 && parts[1].length <= 2
      ? parts[0].replace(/\./g, "") + "." + parts[1]
      : s.replace(/,/g, "");
  } else if (hasDot && !hasComma) {
    const parts = s.split(".");
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3)) s = s.replace(/\./g, "");
  }
  const n = Number(s);
  return Number.isFinite(n) ? n : fallback;
}

function normCur(v, fallback) {
  if (fallback === undefined) fallback = "UNKNOWN";
  const c = asText(v || fallback).toUpperCase();
  if (["CLP", "USD", "EUR", "UNKNOWN"].includes(c)) return c;
  if (/USD|US\$|DOLAR|DÓLAR|DOLARES/i.test(c)) return "USD";
  if (/CLP|PESO/i.test(c)) return "CLP";
  if (/EUR|EURO/i.test(c)) return "EUR";
  return fallback;
}
function getRate(exchange) { return toNum(exchange && (exchange.finalRate || exchange.manualRate || exchange.baseRate), null); }
function convertMoney(amount, currency, exchange) {
  const v = toNum(amount, null), curr = normCur(currency), rate = getRate(exchange);
  if (v === null) return { clp: null, converted: false };
  if (curr === "CLP") return { clp: v, converted: false };
  if ((curr === "USD" || curr === "EUR") && rate && rate > 0) return { clp: Math.round(v * rate), converted: true };
  return { clp: null, converted: false };
}

function firstMatch(text, regex, group) {
  if (group === undefined) group = 1;
  const m = text.match(regex);
  return m ? compact(m[group]) : null;
}
function allRut(text) {
  // Requiere guion para evitar falsos positivos (ej. "583942026").
  const matches = text.match(/\b\d{1,2}\.\d{3}\.\d{3}-[\dkK]\b|\b\d{7,8}-[\dkK]\b/g) || [];
  return [...new Set(matches.map(r => compact(r)))];
}
function normRut(r) { return stripAcc(asText(r)).toLowerCase().replace(/[^0-9k]/g, ""); }

function monthNum(name) {
  const n = normSearch(name);
  const map = { enero: "01", ene: "01", febrero: "02", february: "02", feb: "02", marzo: "03", march: "03", mar: "03",
    abril: "04", april: "04", abr: "04", mayo: "05", may: "05", junio: "06", june: "06", jun: "06",
    julio: "07", july: "07", jul: "07", agosto: "08", august: "08", ago: "08", septiembre: "09", setiembre: "09", sep: "09",
    octubre: "10", october: "10", oct: "10", noviembre: "11", november: "11", nov: "11", diciembre: "12", december: "12", dic: "12" };
  return map[n] || null;
}
function extractDate(text) {
  let m = text.match(/\b(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})\b/);
  if (m) { const yyyy = m[3].length === 2 ? "20" + m[3] : m[3]; return yyyy + "-" + m[2].padStart(2, "0") + "-" + m[1].padStart(2, "0"); }
  m = text.match(/\b(\d{1,2})\s+de\s+([A-Za-zÀ-ɏ]+)\s+(?:del?\s+)?(\d{4})\b/i);
  if (m) { const mm = monthNum(m[2]); if (mm) return m[3] + "-" + mm + "-" + m[1].padStart(2, "0"); }
  m = text.match(/\b(\d{1,2})\s+([A-Za-zÀ-ɏ]+)\s+(\d{4})\b/);
  if (m) { const mm = monthNum(m[2]); if (mm) return m[3] + "-" + mm + "-" + m[1].padStart(2, "0"); }
  return null;
}
function extractDocNumber(text) {
  return firstMatch(text,
    /(?:cotizaci[oó]n\s*(?:n[°ºo.]*)?|n[°º]\s*(?:de\s+cotizaci[oó]n)?|presupuesto\s*n[°º.]?|nro\s*:?|folio\s*n[°º.]?)\s*[:\-#]?\s*([A-Z0-9][A-Z0-9.\/_\-]{2,})/i
  );
}
function detectDocCurrency(text) {
  if (/TOTAL\s*\(\s*D[oó]lar\s*\)|D[oó]lar\s+Observado|Tipo\s+Cambio[\s\S]{0,80}D[oó]lar/i.test(text)) return "USD";
  if (/US\$|USD/i.test(text)) return "USD";
  return "CLP";
}
function detectLineCurrency(line, docCurrency) {
  if (/US\$|USD|U\$S/i.test(line)) return "USD";
  if (/\$/.test(line)) return "CLP";
  return docCurrency;
}

/* --------------- tokenizacion de numeros (separa concatenados) ----------- */
// Un numero "estricto" completo en formato CL (1.234.567,89) o US (1,234,567.89)
// o simple (123 / 123,45 / 123.45).
const STRICT_NUM = /^(?:\d{1,3}(?:\.\d{3})+(?:,\d{1,2})?|\d{1,3}(?:,\d{3})+(?:\.\d{1,2})?|\d+(?:[.,]\d{1,2})?)$/;
function parseStrict(tok) { return STRICT_NUM.test(tok) ? toNum(tok, null) : null; }
// Divide un token que son 2 numeros pegados (ej "33,0033,00", "1,156.0013,872.00").
function splitTwo(tok) {
  for (let k = 1; k < tok.length; k++) {
    const a = tok.slice(0, k), b = tok.slice(k);
    if (STRICT_NUM.test(a) && STRICT_NUM.test(b)) {
      const na = toNum(a, null), nb = toNum(b, null);
      if (na !== null && nb !== null) return [na, nb];
    }
  }
  return null;
}
// Separa un "run" de digitos (posiblemente varios numeros concatenados por
// pdf-parse, ej. "19040,0040,00" = modelo 190 + 40,00 + 40,00) pelando numeros
// completos de DERECHA a IZQUIERDA. Prioriza: decimal (..,dd) > miles > entero.
function flattenNumberRun(raw) {
  let s = String(raw);
  const out = [];
  let guard = 0;
  while (s && guard++ < 20) {
    // Patrones ESPECIFICOS por formato para no cruzar el limite entre dos
    // numeros concatenados (ej. "1.112,001.112,00" -> 1112 y 1112):
    //   CL: miles con punto, decimal con coma   (1.234.567,89)
    //   US: miles con coma, decimal con punto   (1,234,567.89)
    // La parte entera inicial no puede empezar con 0 (salvo "0" solo), para no
    // robar el ultimo cero del numero anterior en concatenaciones.
    let m = s.match(/((?:0|[1-9]\d{0,2})(?:\.\d{3})*,\d{1,2})$/)   // CL con decimal
        || s.match(/((?:0|[1-9]\d{0,2})(?:,\d{3})*\.\d{1,2})$/)    // US con decimal
        || s.match(/([1-9]\d{0,2}(?:\.\d{3})+)$/)                  // CL miles, sin decimal
        || s.match(/([1-9]\d{0,2}(?:,\d{3})+)$/)                   // US miles, sin decimal
        || s.match(/(\d+)$/);                                      // entero simple
    if (!m) break;
    const v = toNum(m[1], null);
    if (v !== null) out.unshift(v);
    s = s.slice(0, s.length - m[1].length);
  }
  return out;
}

/* --------------- builders de item / costo --------------- */
function buildItem(raw, index, exchange, docCurrency) {
  const currency = normCur(raw.lineCurrency || raw.currency || docCurrency, "UNKNOWN");
  const unitPrice = toNum(raw.unitPrice, null), total = toNum(raw.total, null);
  const quantity = toNum(raw.quantity, 1) || 1;
  const uConv = convertMoney(unitPrice, currency, exchange), tConv = convertMoney(total, currency, exchange);
  return {
    lineNumber: toNum(raw.lineNumber, index + 1), itemNumber: toNum(raw.lineNumber, index + 1),
    sku: raw.sku || null, description: compact(raw.description), productName: compact(raw.description),
    quantity, unit: raw.unit || "UN",
    unitPrice, priceUnit: unitPrice, total, priceTotal: total, currency,
    unitPriceOriginal: unitPrice, totalOriginal: total, originalCurrency: currency,
    unitPriceClp: uConv.clp, totalClp: tConv.clp, unitPriceCLP: uConv.clp, totalCLP: tConv.clp,
    convertedToClp: uConv.converted || tConv.converted,
    brand: raw.brand || null, model: raw.model || null, notes: raw.rawLine || null
  };
}
function buildCost(raw, exchange, docCurrency) {
  const currency = normCur(raw.lineCurrency || raw.currency || docCurrency, "UNKNOWN");
  const amount = toNum(raw.amount !== undefined ? raw.amount : raw.total, null);
  const conv = convertMoney(amount, currency, exchange);
  return {
    concept: compact(raw.concept || raw.description || "Costo asociado"),
    amount, currency, amountClp: conv.clp, amountCLP: conv.clp,
    originalAmount: amount, originalCurrency: currency, raw: raw.rawLine || null
  };
}

/* ====================================================================== *
 *  PROVEEDOR
 * ====================================================================== */
// Solo NOMBRE + RUT canonicos (NO productos). Mejora la limpieza del nombre.
const SUPPLIER_BY_RUT = {
  "778527014": { name: "Tecno Mercado Spa", rut: "77.852.701-4" },
  "76492780k": { name: "ADIS Grupo Tecnológico", rut: "76.492.780-k" },
  "778262509": { name: "Comercial Echave Turri Limitada", rut: "77.826.250-9" }
};
const CLIENT_TOKENS = /master\s*drilling|av\.?\s*aeropuerto\s*9970|ricardo\s+d[ií]az|servicios?\s+para\s+la\s+miner[ií]a|ignacio\s+maulen|francisco\s+cris[oó]stomo|francisco\s+crisotomo|gonzalo\s+diaz/i;
const FORBIDDEN_SUPPLIER = /^(t[eé]rmino|tipo\s+camb|ejecutivo|fecha|modo\s+env[ií]o|señores?|contacto|comuna|cliente|direcci[oó]n|giro|att?\.?|estimado|presente|cargo|fono|tel[eé]fono|mail|e-?mail|correo|banco|cuenta|rut|r\.u\.t|nº|n°|cotizaci[oó]n|vendedor|centro\s+costo|atenci[oó]n|c\.costo|telefono)/i;

function cleanSupplierName(value) {
  let n = compact(value)
    .replace(/\s*[\-,]?\s*(?:r\.?u\.?t\.?|rut)\s*[:.]?\s*\d[\d.\-kK]*.*$/i, "")
    .replace(/\s*cotizaci[oó]n.*$/i, "")
    .replace(/\s*nro?\b.*$/i, "")
    .replace(/\s*n[°º]\b.*$/i, "")
    .replace(/^\s*(nombre|empresa|raz[oó]n\s+social)\s*:\s*/i, "")
    .replace(/[._]{2,}/g, " ")
    .replace(/\s{2,}/g, " ").trim().replace(/[.,\-\s]+$/g, "").trim();
  return compact(n);
}
function supplierFromDomain(text) {
  const emails = [...text.matchAll(/\b([a-z0-9._%-]+)@([a-z0-9.-]+\.[a-z]{2,})\b/gi)];
  for (const e of emails) {
    const base = e[2].replace(/^www\./i, "").split(".")[0];
    if (base && base.length >= 3 && !/gmail|hotmail|yahoo|outlook|live|icloud|masterdrilling/i.test(base))
      return base.replace(/-/g, " ").toUpperCase();
  }
  const web = text.match(/\bwww\.([a-z0-9\-]{3,})\.(?:cl|com|net|org)\b/i);
  if (web && !/masterdrilling/i.test(web[1])) return web[1].replace(/-/g, " ").toUpperCase();
  return null;
}

// Regla 9: 1) RUT conocido 2) "Emitir OC"/Datos OC/NOMBRE/Razon Social
//          3) dominio/correo 4) encabezado con forma legal. Nunca cliente.
function extractSupplier(text) {
  const lines = norm(text).split("\n").map(l => l.trim()).filter(Boolean);
  const rutList = allRut(text);
  const normRuts = rutList.map(normRut);

  // 1) RUT conocido
  for (const key of Object.keys(SUPPLIER_BY_RUT))
    if (normRuts.includes(key)) return { name: SUPPLIER_BY_RUT[key].name, rut: SUPPLIER_BY_RUT[key].rut, confidence: 0.99 };

  let name = null, rut = null;

  // 2) marcadores explicitos de proveedor (NOMBRE antes que "Datos para OC"
  //    para no capturar la palabra "NETO" intermedia del layout roto).
  name = firstMatch(text, /Emitir\s+Orden(?:es)?\s+de\s+Compra\s+a\s*:?\s*([^\n\r]{3,70})/i)
      || firstMatch(text, /NOMBRE\s*:\s*([^\n\r]{3,70})/i)
      || firstMatch(text, /Raz[oó]n\s+Social\s*:\s*([^\n\r]{3,80})/i);
  if (name) name = cleanSupplierName(name);
  if (name && (FORBIDDEN_SUPPLIER.test(name) || CLIENT_TOKENS.test(name) || /^neto$/i.test(name))) name = null;

  // 3) encabezado: primeras lineas con forma legal y sin tokens de cliente
  if (!name) {
    for (const line of lines.slice(0, 8)) {
      const cl = cleanSupplierName(line);
      if (cl.length < 4 || cl.length > 70) continue;
      if (FORBIDDEN_SUPPLIER.test(cl) || CLIENT_TOKENS.test(cl)) continue;
      if (/santiago|providencia|cerrillos|chile s\.a/i.test(cl)) continue;
      if (/\b(S\.?A\.?|LTDA\.?|LIMITADA|E\.?I\.?R\.?L\.?|SPA|SAC|COMERCIAL|SERVICIOS?|SOLUCIONES?|INGENier[ií]a|INTEGRALES|GRUPO|DISTRIBUIDORA|IMPORTADORA)\b/i.test(cl)) { name = cl; break; }
    }
  }

  // 4) dominio / correo
  if (!name) name = supplierFromDomain(text);

  // RUT del proveedor: cercano a marcador de OC/NOMBRE, o el primer RUT que NO
  // este junto a "cliente"/Master Drilling.
  const provSection = text.match(/(?:Emitir\s+Orden(?:es)?\s+de\s+Compra\s+a|Datos\s+para\s+Orden\s+de\s+Compra|NOMBRE\s*:|Raz[oó]n\s+Social\s*:)[\s\S]{0,200}/i);
  if (provSection) { const r = allRut(provSection[0])[0]; if (r) rut = r; }
  if (!rut) {
    for (const cand of rutList) {
      const idx = text.indexOf(cand);
      const around = idx >= 0 ? text.slice(Math.max(0, idx - 45), idx + 45) : "";
      if (/cliente\s*:/i.test(around) || CLIENT_TOKENS.test(around)) continue;
      rut = cand; break;
    }
  }

  const finalName = name ? cleanSupplierName(name) : "Proveedor no identificado";
  return { name: finalName || "Proveedor no identificado", rut: rut || null,
    confidence: finalName && finalName !== "Proveedor no identificado" ? 0.8 : 0.25 };
}

function extractTerms(text) {
  return {
    paymentTerms: firstMatch(text, /(?:forma\s+de\s+pago|condici[oó]n(?:es)?\s+de\s+pago|t[eé]rmino\s+comercial|tipo\s+de\s+pago)\s*[:.]\s*([^\n]+)/i) || null,
    deliveryTime: firstMatch(text, /plazo\s+de\s+entrega\s*[:.]?\s*([^\n]+)/i) || firstMatch(text, /modo\s+env[ií]o\s*[:.]?\s*([^\n]+)/i) || null,
    availability: firstMatch(text, /(?:vigencia|v[aá]lida?|validez|vencimiento)[^\n:]*[:.]?\s*([^\n]+)/i) || firstMatch(text, /(hasta\s+agotar\s+stock)/i) || null
  };
}

/* ----------------------------- costos / rechazos ----------------------- */
// Sin \b final: el texto suele venir pegado al codigo/siguiente palabra.
const ASSOC_COST_RE = /(despacho|flete|env[ií]o|log[ií]stic[ao]|entrega|retiro|transporte|gastos?\s+(?:de\s+)?operaci[oó]n|cargo\s+log[ií]stico|cobro\s+log[ií]stic)/i;
const CONDITIONAL_RE = /\b(si\s+aplica|en\s+caso\s+de|por\s+compras?\s+inferiores?|inferiores?\s+a|fuera\s+del?\s+per[ií]metro|fuera\s+de\s+santiago|seg[uú]n\s+destino|cargo\s+del\s+cliente|cuenta\s+del\s+cliente|despacho\s+a\s+provincia|a\s+convenir|consulte\s+por)\b/i;
function isAssocCost(d) { return ASSOC_COST_RE.test(d); }
function isConditional(l) { return CONDITIONAL_RE.test(l); }

// Lineas que NUNCA son un item (rule 10).
const REJECT_LINE = /(^|\b)(santiago|se[ñn]ores?|presente|estimado|att?\b|atenci[oó]n|master\s*drilling|dep[oó]sitos?|transferencias?|banco|cta\.?\s*corriente|cuenta\s+corriente|tel[eé]fono|telefono|fono|celular|e-?mail|correo|p[aá]gina|condiciones?|observaci|forma\s+de\s+pago|plazo\s+de|vigencia|validez|vencimiento|direcci[oó]n|giro|ejecutiv|vendedor|centro\s+costo|c\.costo|comuna|garant[ií]a|al\s+d[ií]a\s+de\s+hoy|nueva\s+llegada|stock|disponibl|firma|alcances?|conexi|materiales|peso|dimensiones|espesor|transparencia|tama[ñn]o|implementaci[oó]n|reforzar|planchas?\s+de|perfil\s+\d|requisitos?|aud(?:io|iovisual)|servicios?\s+(?:para|adicional|fuera))(\b|:)/i;
const DATE_START = /^\s*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}|\d{1,2}\s+de\s+[a-zà-ÿ]+|al\s+d[ií]a\s+de\s+hoy)/i;
const TOTALS_LINE = /^(sub\s*total|total\s*neto|total\s*pagar|total\s*general|total\s*cotiz|total\s*\(?\s*d[oó]lar|total\b|neto\b|i\.?v\.?a\.?\b|iva\b|ila\b|ahorro|descuento|registros?)\b/i;

function hasProductLetters(desc) {
  const letters = (desc.match(/[A-Za-zÀ-ɏ]/g) || []).length;
  return letters >= 3 && /[A-Za-zÀ-ɏ]{3,}/.test(desc) && /[aeiouà-ÿAEIOU]/i.test(desc);
}

/* --------------- nucleo: parseo de fila por invariante --------------- */
// Extrae SKU/codigo aparente para no perderlo (no afecta numeros).
function guessSku(raw) {
  const m = raw.match(/\bP\/N\s*([A-Z0-9][A-Z0-9\-]{2,})/i) || raw.match(/\b([A-Z]{1,4}\d{3,}[A-Z0-9\-]*)\b/) || raw.match(/\b(\d{4,}-[\dA-Z\-]+)\b/);
  return m ? compact(m[1]) : null;
}

const TABLE_HEADER = /(descripci[oó]n|detalle|glosa|producto).{0,40}(cant|cantidad|precio|valor|unit|total)|(c[oó]digo|item|n[°º]).{0,30}(descripci[oó]n|producto)|cantidad.{0,20}c[oó]digo|descripci[oó]n.{0,20}unitario/i;
const STOP_TABLE = /^(sub\s*total|total\s+neto|total\s*pagar|total\s*general|total\s*cotiz|total\s*\(?\s*d[oó]lar|total\s*:|neto\s*[:$]|neto$|datos\s+para\s+orden|condiciones|observaci|atentamente|firma|los\s+leones|p[aá]gina\s+\d)/i;
// Sub-encabezados de columnas (no son texto de producto ni item). Prefijo:
// tolera puntuacion final ("Sin I.V.A.", "T/CItem", "Cant.").
const SUBHEADER = /^(sin\s+i\.?v\.?a|t\/c|item\b|unitario|cantidad|c[oó]digo|descripci[oó]n|precio|valor\s+unit|totales|und\b|marca\b|periodo|detalle|glosa|cant\b|valor\s+x)/i;

// Intenta parsear una fila valorizada inline (>=2 numeros en la linea).
// Devuelve item o null. pendingDesc se usa si la descripcion viene en lineas previas.
function parsePricedRow(rawLine, docCurrency, pendingDesc) {
  let raw = compact(rawLine);
  if (!raw) return null;
  if (DATE_START.test(raw)) return null;
  if (REJECT_LINE.test(normSearch(raw))) return null;

  const lineCur = detectLineCurrency(raw, docCurrency);

  // base: simbolos de moneda y parentesis -> espacios (longitud preservada).
  // No se enmascaran codigos: el tokenizador RTL separa modelo+precio pegados.
  const base = raw.replace(/US\$/gi, m => " ".repeat(m.length)).replace(/U\$S/gi, "   ").replace(/\$/g, " ").replace(/[()]/g, " ");

  const runs = [];
  const re = /\d[\d.,]*/g; let mm;
  while ((mm = re.exec(base)) !== null) runs.push({ raw: mm[0], idx: mm.index, len: mm[0].length });
  if (runs.length === 0) return null;

  const flat = [];
  for (let r = 0; r < runs.length; r++)
    for (const n of flattenNumberRun(runs[r].raw)) flat.push({ value: n, runI: r });
  if (flat.length < 2) return null;

  const total = flat[flat.length - 1].value;
  const unit = flat[flat.length - 2].value;
  if (!(total > 0) || !(unit > 0)) return null;

  // Guard anti-fragmento: numeros chicos sin separador ni simbolo de moneda
  // suelen ser trozos de un codigo (ej. "P/N 2HWN3" -> 2 y 3). Rechazar.
  const hasSym = /US\$|U\$S|\$/.test(raw);
  const totRaw = runs[flat[flat.length - 1].runI].raw, uniRaw = runs[flat[flat.length - 2].runI].raw;
  if (!hasSym && total < 100 && unit < 100 && !/[.,]/.test(totRaw) && !/[.,]/.test(uniRaw)) return null;

  const tol = Math.max(1, 0.02 * Math.abs(total));
  let qty = null, qtyRunI = -1;
  for (let i = flat.length - 3; i >= 0; i--) {
    const q = flat[i].value;
    if (Number.isInteger(q) && q >= 1 && q < 10000 && Math.abs(q * unit - total) <= tol) { qty = q; qtyRunI = flat[i].runI; break; }
  }
  if (qty === null) {
    // fallback: digitos pegados justo antes del precio unitario (qty glued a codigo)
    const unitIdx = runs[flat[flat.length - 2].runI].idx;
    const pre = raw.slice(0, unitIdx).match(/(\d{1,4})\D{0,3}$/);
    if (pre) { const q = parseInt(pre[1], 10); if (q >= 1 && q < 10000 && Math.abs(q * unit - total) <= tol) qty = q; }
  }
  if (qty === null) {
    if (Math.abs(unit - total) <= tol) qty = 1;
    else return null; // no cuadra qty*unit~=total -> NO es item (anti-basura)
  }

  // Descripcion: borra runs usados (unit/total/qty), conserva numeros de desc.
  const usedRuns = new Set([flat[flat.length - 1].runI, flat[flat.length - 2].runI]);
  if (qtyRunI >= 0) usedRuns.add(qtyRunI);
  let descWork = base;
  for (const rn of [...usedRuns].map(ri => runs[ri]).sort((a, b) => b.idx - a.idx))
    descWork = descWork.slice(0, rn.idx) + " ".repeat(rn.len) + descWork.slice(rn.idx + rn.len);
  let desc = compact(descWork).replace(/^\s*\d{1,3}(?=\D)/, "").trim(); // quita numero de item inicial

  if ((!hasProductLetters(desc) || desc.length < 4) && pendingDesc && hasProductLetters(pendingDesc))
    desc = compact(pendingDesc + " " + desc);
  desc = compact(desc.replace(/\b(UND|UN|UNI|GL|CU|SERV|PACK|SET|MES|D[IÍ]A|HORA|KG|LT|MT|EA|BOL|CJA|PQT|DP|BOX)\b\s*$/i, ""))
    .replace(/^\s*\d{1,3}(?=\D)/, "").trim();

  // Si la descripcion empieza con un codigo/SKU pegado, separarlo.
  let sku = guessSku(raw);
  const skuLead = desc.match(/^([A-Za-zÀ-ÿ]{0,4}\d{3,}[A-Za-z0-9\-]*)\s*/);
  if (skuLead) {
    const rest = compact(desc.slice(skuLead[0].length));
    if (hasProductLetters(rest)) { desc = rest; if (!sku) sku = skuLead[1]; }
  }

  if (!hasProductLetters(desc)) return null;
  if (REJECT_LINE.test(normSearch(desc))) return null;

  return { sku, description: desc, quantity: qty, unit: "UN", unitPrice: unit, total, lineCurrency: lineCur, rawLine: raw };
}

// Linea que es solo un numero de dinero (precio en su propia linea).
function moneyOnlyValue(line) {
  const s = line.replace(/US\$/gi, " ").replace(/\$/g, " ").replace(/[()]/g, " ").trim();
  if (!/^[\d.,]+$/.test(s)) return null;
  if (!(/[.,]\d{2}$/.test(s) || toNum(s, 0) >= 100)) return null; // descarta itemNo sueltos
  const nums = flattenNumberRun(s);
  return nums.length ? nums[nums.length - 1] : null;
}

/* --------------- parser de tabla: bounding por header + acumuladores ----- */
function extractRows(text, docCurrency, warnings) {
  const lines = norm(text).split("\n").map(l => compact(l)).filter(Boolean);
  const items = [], costs = [];
  let pendingDesc = "", pendingNums = [];
  const resetPending = () => { pendingDesc = ""; pendingNums = []; };

  const headerIdx = lines.findIndex(l => TABLE_HEADER.test(normSearch(l)));
  const start = headerIdx >= 0 ? headerIdx + 1 : 0;
  const strict = headerIdx < 0; // sin tabla: exigir simbolo de moneda por fila

  const emit = (row, srcLine) => {
    if (isAssocCost(row.description)) {
      if (isConditional(srcLine) || isConditional(pendingDesc)) warnings.push("Costo condicional no aplicado: " + row.description);
      else costs.push(row);
    } else items.push(row);
    resetPending();
  };

  for (let i = start; i < lines.length; i++) {
    const line = lines[i];
    const search = normSearch(line);

    if ((items.length > 0 || costs.length > 0) && STOP_TABLE.test(search)) break; // fin de tabla
    if (/^item$/i.test(line)) { resetPending(); continue; }    // nuevo bloque ITEM
    if (/^\d{1,3}$/.test(line)) { resetPending(); continue; }  // numero de item suelto -> nuevo bloque
    if (SUBHEADER.test(line)) continue;
    if (TOTALS_LINE.test(search)) { resetPending(); continue; }

    const hasCur = /US\$|U\$S|\$/.test(line);
    const row = (!strict || hasCur) ? parsePricedRow(line, docCurrency, pendingDesc) : null;
    if (row) { emit(row, line); continue; }

    // Precio en linea propia -> acumular numeros y emitir cuando haya 2 + desc.
    const mv = (!strict || hasCur) ? moneyOnlyValue(line) : null;
    if (mv !== null) {
      pendingNums.push(mv);
      if (pendingNums.length >= 2 && hasProductLetters(pendingDesc)) {
        const unit = pendingNums[pendingNums.length - 2], total = pendingNums[pendingNums.length - 1];
        const tol = Math.max(1, 0.02 * Math.abs(total));
        let qty = 1;
        if (unit > 0 && Math.abs(unit - total) > tol) { const q = Math.round(total / unit); if (q >= 1 && q < 10000 && Math.abs(q * unit - total) <= tol) qty = q; else { continue; } }
        emit({ sku: guessSku(pendingDesc), description: compact(pendingDesc), quantity: qty, unit: "UN", unitPrice: unit, total, lineCurrency: detectLineCurrency(line, docCurrency), rawLine: pendingDesc + " " + line }, line);
      }
      continue;
    }

    if (DATE_START.test(line) || REJECT_LINE.test(search)) continue;
    if (hasProductLetters(line) && line.length >= 4) {
      pendingDesc = pendingDesc ? compact(pendingDesc + " " + line) : line;
      if (pendingDesc.length > 320) pendingDesc = line;
    }
  }

  // dedup
  const seen = new Set(), uItems = [];
  for (const it of items) {
    const k = normSearch(it.description) + "|" + it.quantity + "|" + it.unitPrice + "|" + it.total + "|" + it.lineCurrency;
    if (seen.has(k)) continue; seen.add(k); uItems.push(it);
  }
  return { items: uItems, costs };
}

/* --------------- totales --------------- */
function explicitTotals(text) {
  const clean = norm(text);
  const getLast = re => { const ms = [...clean.matchAll(re)]; return ms.length ? toNum(ms[ms.length - 1][1], null) : null; };
  return {
    subtotal: getLast(/(?:sub\s*total|total\s+neto|neto)\s*[:\$\s]*\$?\s*([\d.,]+)/gi),
    tax: getLast(/(?:i\.?v\.?a\.?|iva)\s*[:\$\s]*\$?\s*([\d.,]+)/gi),
    total: getLast(/total\s*(?:a\s+pagar|final|pagar|general)?\s*[:\$\s]*\$?\s*([\d.,]+)/gi),
    value: getLast(/(?:valor\s+del?\s+servicio|costos?\s+del?\s+servicio|^\s*valor[_\s.:]*)\s*\$?\s*([\d.,]+)/gim),
    hasPlusIva: /\+\s*iva|no\s+incluyen?\s+i\.?v\.?a|valores?\s+netos?\s*\+\s*iva/i.test(clean)
  };
}
function extractGlobalDesc(text) {
  const lines = norm(text).split("\n").map(l => compact(l)).filter(Boolean);
  const STOP = /^(cotizaci[oó]n|santiago|señores?|presente|at\.?|estimado|valor|costos?|emitir|rut|direcci[oó]n|atentamente|gerente|datos para|neto|iva|total|fecha|n[°º]|item|descripci[oó]n|observaci|condiciones|alcances|materiales|peso|dimensiones|espesor|tama[ñn]o|implementaci)/i;
  const cands = lines.filter(l => l.length > 8 && l.length < 160).filter(l => !STOP.test(l))
    .filter(l => !CLIENT_TOKENS.test(l)).filter(l => !/\b\d{1,2}\.?\d{3}\.?\d{3}-?[\dkK]\b/.test(l)).filter(l => !/^\d+$/.test(l));
  const strong = cands.find(l => /\b(instalaci[oó]n|cierre|reja|servicio|arriendo|notebook|malla|suministro|mantenci[oó]n|reparaci[oó]n|proyecto|equipo)\b/i.test(l));
  return strong || cands[0] || "Servicio cotizado";
}

/* ============================ documento ============================== */
function buildDocument(source, index) {
  const text = source.textForAI || source.rawTextPreview || "";
  const exchange = source.exchange || {};
  const warnings = [...(source.warnings || [])];
  const docCurrency = detectDocCurrency(text);
  const supplier = extractSupplier(text);
  const terms = extractTerms(text);

  const { items: rawItems, costs: rawCosts } = extractRows(text, docCurrency, warnings);

  let items = rawItems.map((it, i) => buildItem(it, i, exchange, docCurrency));
  let associatedCosts = rawCosts.map(c => buildCost({ concept: c.description, total: c.total, lineCurrency: c.lineCurrency, rawLine: c.rawLine }, exchange, docCurrency));

  // Aviso de flete/cargo condicional (no se aplica como costo).
  const fleteCond = text.match(/(?:flete|despacho|cargo)[^\n]{0,80}(?:inferiores?\s+a|fuera\s+de\s+santiago|provincia|si\s+aplica|cargo\s+del\s+cliente)[^\n]{0,40}/i);
  if (fleteCond) warnings.push("Condicion de flete/despacho informada (no aplicada como costo): " + compact(fleteCond[0]));

  const tot = explicitTotals(text);

  // Documento de servicio global (sin tabla): 1 item desde el valor neto.
  if (items.length === 0) {
    let globalValue = tot.subtotal !== null ? tot.subtotal : (tot.value !== null ? tot.value : null);
    // Validar: el monto debe aparecer en el texto con separador de miles
    // (evita capturar numeros pegados tipo "583942026" = cotizacion+anio).
    if (globalValue !== null && globalValue >= 1000) {
      const fmt = globalValue.toLocaleString("es-CL");
      if (!text.includes(fmt)) globalValue = null;
    }
    if (globalValue !== null && globalValue > 0) {
      items = [buildItem({ lineNumber: 1, sku: null, description: extractGlobalDesc(text), quantity: 1, unit: "SERV", unitPrice: globalValue, total: globalValue, lineCurrency: docCurrency }, 0, exchange, docCurrency)];
      warnings.push((source.fileName || "archivo") + ": item global creado desde valor neto/servicio del documento.");
    }
  }
  if (tot.hasPlusIva) warnings.push("Valores netos + IVA segun el documento.");

  // Moneda mixta?
  const curs = new Set(items.map(i => i.originalCurrency).filter(c => c && c !== "UNKNOWN"));
  const mixedCurrency = curs.size > 1;

  // Totales: preferir SUMA de items + costos (robusto frente al layout roto),
  // con IVA 19%. Si no hay items pero hay total explicito, usarlo.
  const itemsClpOk = items.length > 0 && items.every(i => i.totalClp !== null);
  let subtotalClp = null, taxClp = null, totalClp = null;
  if (items.length > 0 && itemsClpOk) {
    subtotalClp = items.reduce((a, i) => a + (i.totalClp || 0), 0) + associatedCosts.reduce((a, c) => a + (c.amountClp || 0), 0);
    taxClp = Math.round(subtotalClp * 0.19);
    totalClp = subtotalClp + taxClp;
  } else {
    const sc = convertMoney(tot.subtotal !== null ? tot.subtotal : tot.value, docCurrency, exchange);
    subtotalClp = sc.clp;
    taxClp = tot.tax !== null ? convertMoney(tot.tax, docCurrency, exchange).clp : (subtotalClp !== null ? Math.round(subtotalClp * 0.19) : null);
    totalClp = subtotalClp !== null && taxClp !== null ? subtotalClp + taxClp : convertMoney(tot.total, docCurrency, exchange).clp;
  }

  // Subtotal/IVA/total en moneda original (si moneda unica), util para mostrar.
  let subtotal = null, tax = null, total = null, totalsCurrency = mixedCurrency ? "CLP" : docCurrency;
  if (!mixedCurrency && items.length > 0) {
    const sameCur = items.every(i => i.originalCurrency === items[0].originalCurrency) ? items[0].originalCurrency : docCurrency;
    totalsCurrency = sameCur;
    subtotal = items.reduce((a, i) => a + (i.total || 0), 0) + associatedCosts.reduce((a, c) => a + (c.amount || 0), 0);
    tax = Math.round(subtotal * 0.19);
    total = subtotal + tax;
  } else if (mixedCurrency) {
    subtotal = subtotalClp; tax = taxClp; total = totalClp; totalsCurrency = "CLP";
  } else {
    subtotal = tot.subtotal !== null ? tot.subtotal : tot.value;
    tax = tot.tax; total = tot.total;
  }

  if (!supplier.rut) warnings.push((source.fileName || "archivo") + ": no se identifico RUT del proveedor.");
  const isValid = items.length > 0;
  if (!isValid) warnings.push((source.fileName || "archivo") + ": no se extrajo ningun item valido (revisar OCR/formato).");

  return {
    fileName: source.fileName || ("archivo_" + (index + 1) + ".pdf"),
    fileKind: "pdf", ext: "pdf", mimeType: "application/pdf",
    detectedType: isValid ? "quotation" : "unknown", isValidQuotation: isValid, valid: isValid, omitted: !isValid,
    supplierName: supplier.name, supplierRut: supplier.rut,
    supplier: { name: supplier.name, rut: supplier.rut, confidence: supplier.confidence },
    documentNumber: extractDocNumber(text), documentDate: extractDate(text),
    currency: totalsCurrency, mixedCurrency,
    normalizedCurrency: normCur((exchange && exchange.targetCurrency) || "CLP", "CLP"),
    paymentTerms: terms.paymentTerms, deliveryTime: terms.deliveryTime, availability: terms.availability,
    subtotal, tax, total, shippingCost: null,
    subtotalClp, taxClp, totalClp,
    quoteSubtotal: subtotal, quoteTax: tax, quoteTotal: total,
    quoteSubtotalClp: subtotalClp, quoteTaxClp: taxClp, quoteTotalClp: totalClp,
    associatedCosts, items,
    rawTextPreview: source.rawTextPreview || "",
    extractionMetadata: source.extractionMetadata || {},
    warnings
  };
}

/* ============================ orquestacion ============================== */
const documents = [], omittedFiles = [], warnings = [], errors = [];
let jobId = null, exchange = {}, evaluationData = {};

for (let i = 0; i < sourceItems.length; i++) {
  const source = sourceItems[i] && sourceItems[i].json ? sourceItems[i].json : {};
  jobId = jobId || source.jobId || null;
  exchange = source.exchange || exchange;
  evaluationData = source.evaluationData || evaluationData;

  let doc;
  try {
    doc = buildDocument(source, i);
  } catch (err) {
    doc = {
      fileName: source.fileName || ("archivo_" + (i + 1) + ".pdf"),
      fileKind: "pdf", ext: "pdf", mimeType: "application/pdf",
      detectedType: "unknown", isValidQuotation: false, valid: false, omitted: true,
      supplierName: "Proveedor no identificado", supplierRut: null,
      supplier: { name: "Proveedor no identificado", rut: null, confidence: 0 },
      documentNumber: null, documentDate: null, currency: "CLP", mixedCurrency: false, normalizedCurrency: "CLP",
      paymentTerms: null, deliveryTime: null, availability: null,
      subtotal: null, tax: null, total: null, shippingCost: null,
      subtotalClp: null, taxClp: null, totalClp: null,
      quoteSubtotal: null, quoteTax: null, quoteTotal: null,
      associatedCosts: [], items: [],
      rawTextPreview: source.rawTextPreview || "", extractionMetadata: source.extractionMetadata || {},
      warnings: ["Error interno del parser: " + (err && err.message ? err.message : String(err))]
    };
    errors.push((source.fileName || "archivo") + ": " + (err && err.message ? err.message : String(err)));
  }

  documents.push(doc);
  if (doc.warnings) warnings.push.apply(warnings, doc.warnings);
  if (!doc.isValidQuotation) {
    omittedFiles.push({
      fileName: doc.fileName, fileKind: "pdf", ext: "pdf", mimeType: "application/pdf",
      detectedType: doc.detectedType, supplierName: doc.supplierName, supplierRut: doc.supplierRut,
      reason: "No se pudieron extraer items valorizados.",
      missingFields: ["items valorizados"], action: "Revisar si el PDF contiene texto seleccionable."
    });
  }
}

const preOmitted = (sourceItems[0] && sourceItems[0].json && sourceItems[0].json.omittedFiles) || [];
for (const o of preOmitted) if (!omittedFiles.some(x => x.fileName === o.fileName)) omittedFiles.push(o);

